CREATE OR REPLACE FUNCTION reindex_superhero_ids(IN BIGINT) 
RETURNS VOID 
LANGUAGE plpgsql 
AS $$ 
BEGIN
    CREATE TEMPORARY SEQUENCE IF NOT EXISTS id_seq_temp MINVALUE 1 START WITH 1 INCREMENT BY 1;
    ALTER SEQUENCE id_seq_temp RESTART WITH 1;

    UPDATE superhero 
    SET hair_colour_id = hair_colour_id + 2000 
    WHERE publisher_id = $1;

    UPDATE superhero 
    SET hair_colour_id = nextval('id_seq_temp') 
    WHERE publisher_id = $1
    ORDER BY id;

    DROP SEQUENCE IF EXISTS id_seq_temp;
END;
$$

CREATE OR REPLACE FUNCTION calculate_loan_status() 
RETURNS SETOF loan_last
AS $$
BEGIN 
    INSERT INTO loan_last 
    SELECT loan_id, status FROM loan_first WHERE status = 'A'; 

    RETURN QUERY SELECT * FROM loan_last;
END; 
$$ LANGUAGE plpgsql

DROP FUNCTION IF EXISTS update_school_inventory_after_supply() CASCADE;

CREATE OR REPLACE FUNCTION update_school_inventory_after_supply()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $trigger$
BEGIN
    UPDATE school_inventory AS i
    SET quantity = i.quantity + NEW.quantity
    WHERE i.cdscode = NEW.cdscode
      AND i.supply_name = NEW.supply_name;

    RETURN NEW;
END;
$trigger$;

DROP TRIGGER IF EXISTS trigger_insert_supply ON school_supplies;

CREATE TRIGGER trigger_insert_supply
    AFTER INSERT ON school_supplies
    FOR EACH ROW
    EXECUTE FUNCTION update_school_inventory_after_supply()

