-- Create EventCategories table first
CREATE TABLE [dbo].[EventCategories](
    [ID] [int] IDENTITY(1,1) NOT NULL PRIMARY KEY,
    [IsBusinessCategory] [bit] NULL
);

-- Create BusinessCategories table with foreign key
CREATE TABLE [dbo].[BusinessCategories](
    [ID] [int] IDENTITY(1,1) NOT NULL PRIMARY KEY,
    [BusinessCategoryID] [INT] NOT NULL,
    FOREIGN KEY ([BusinessCategoryID]) REFERENCES [dbo].[EventCategories]([ID]),
    CONSTRAINT CHK_IsBusinessCategory CHECK (
        [dbo].[fn_CheckIsBusinessCategory]([BusinessCategoryID]) = 1
    )
);

-- Create a function to check if the category is a business category
GO
CREATE FUNCTION [dbo].[fn_CheckIsBusinessCategory](@CategoryID INT)
RETURNS BIT
AS
BEGIN
    DECLARE @IsBusinessCategory BIT;

    SELECT @IsBusinessCategory = [IsBusinessCategory]
    FROM [dbo].[EventCategories]
    WHERE [ID] = @CategoryID;

    RETURN ISNULL(@IsBusinessCategory, 0);
END;
GO

